<template>
    <div class="RightSideMiddle-container module-container" ref="RightSideMiddleContainer">
        <svg width="0" height="0" >
            <defs>
                <linearGradient id="blue" x1="0%" y1="0%"
                                x2="100%" y2="0%">
                    <stop offset="0%" style="stop-color:#0CB9FF" stop-opacity="1"></stop>
                    <stop offset="100%" style="stop-color:#2f66a6" stop-opacity="1"></stop>
                </linearGradient>
            </defs>
        </svg>
        <svg width="0" height="0" >
            <defs>
                <linearGradient id="red" x1="0%" y1="0%"
                                x2="100%" y2="0%">
                    <stop offset="0%" style="stop-color:#6DFEFF" stop-opacity="1"></stop>
                    <stop offset="100%" style="stop-color:#05AE93" stop-opacity="1"></stop>
                </linearGradient>
            </defs>
        </svg>
        <div class="title">开发周期</div>
        <div class="content_top_border"></div>
        <div class="dev-container">
            <div class="dev-week" >
                开发周
            </div>
            <div class="dev-week-box">
                <div v-if="gettersStaffData.teamDev.length < 5">
                    <div class="my-progress-dev"
                         :key="index"
                         v-for="(i,index) in gettersStaffData.teamDev">
                        <el-progress type="circle"
                                     :stroke-width="9"
                                     :width="70"
                                     :percentage="i.num">
                        </el-progress>
                        <div class="progress-text">{{i.label}}</div>
                    </div>
                </div>
                <vue-scroll
                        v-else
                        :data="gettersStaffData.teamDev" :class-option="optionLeft"
                        :style="{width:seamlessDevWidth + 'px'}"
                        class="seamless-warp2">
                    <ul class="item"
                        :style="{width:seamlessDevUlWidth + 'px'}"
                    >
                        <li v-for="(i,index) in gettersStaffData.teamDev"
                            class="dev-week-box-item"
                            :key="index"
                        >
                            <div class="my-progress-dev">
                                <el-progress type="circle"
                                             :stroke-width="9"
                                             :width="70"
                                             :percentage="i.num">
                                </el-progress>
                                <div class="progress-text">{{i.label}}</div>
                            </div>
                        </li>
                    </ul>
                </vue-scroll>
            </div>
            <div class="dev-week" style="margin-top: 5px">
                测试周
            </div>
            <div class="dev-week-box">
                <div v-if="gettersStaffData.teamTest.length<5">
                    <div class="dev-week-box-item"
                         v-for="(i,index) in gettersStaffData.teamTest"
                    >
                        <div class="my-progress-test">
                            <el-progress type="circle"
                                         :stroke-width="9"
                                         :width="70"
                                         :percentage="i.num">
                            </el-progress>
                            <div class="progress-text">{{i.label}}</div>
                        </div>
                    </div>
                </div>
                <vue-scroll
                        v-else
                        :style="{width:seamlessTestWidth + 'px'}"
                        :data="gettersStaffData.teamTest" :class-option="optionLeft" class="seamless-warp2">
                    <ul class="item"
                        :style="{width:seamlessTestUlWidth + 'px'}"
                    >
                        <li v-for="(i,index) in gettersStaffData.teamTest"
                            class="dev-week-box-item"
                            :key="index"
                        >
                            <div class="my-progress-test">
                                <el-progress type="circle"
                                             :stroke-width="9"
                                             :width="70"
                                             :percentage="i.num">
                                </el-progress>
                                <div class="progress-text">{{i.label}}</div>
                            </div>
                        </li>
                    </ul>
                </vue-scroll>
            </div>
        </div>
        <div class="content_bottom_border"></div>
    </div>
</template>

<script>

import { mapGetters,mapActions } from 'vuex'
import vueScroll from 'vue-seamless-scroll'

export default {

  name: "RightSideMiddle",

  data() {
    return {
      devData:[],
      devShowData:[],
      mySwiper:'',
      colorA: [
        {offset: 0, color: '#0CB9FF'},
        {offset: 0.5, color: '#208BFF'},
        {offset: 1, color: '#2f66a6'}
      ],
      colorB: [
        {offset: 1, color: '#1F426C'}
      ],
      colorC: [
        {offset: 0, color: '#6DFEFF'},
        {offset: 0.5, color: '#05d9b9'},
        {offset: 1, color: '#05AE93'}
      ],
      colorD: [
        {offset: 1, color: '#05745f'}
      ]
    }
  },
  mounted() {

  },
  computed: {
   ...mapGetters([
     'gettersStaffData'
   ]),
    optionLeft () {
      return {
        direction: 2,
        limitMoveNum:4
      }
    },
    seamlessDevWidth(){
      return this.gettersStaffData.teamDev.length * 80
    },
    seamlessDevUlWidth(){
      if(this.gettersStaffData.teamDev.length < 5){
        return this.seamlessDevWidth
      }else {
        return this.seamlessDevWidth + (this.gettersStaffData.teamDev.length * 10)
      }
    },
    seamlessTestWidth(){
      return this.gettersStaffData.teamTest.length * 80
    },
    seamlessTestUlWidth(){
     if(this.gettersStaffData.teamTest.length < 5){
       return this.seamlessTestWidth
     }else {
       return this.seamlessTestWidth + (this.gettersStaffData.teamTest.length * 10)
     }
    }
  },
  components: {
    vueScroll
  },

  methods: {
    ...mapActions([
      'getStaffData'
    ]),

  }

}
</script>

<style scoped lang="scss">
    .RightSideMiddle-container {
        padding-top: 20px;
        padding-left:18px;
        .seamless-warp2 {
            overflow: hidden;
            height: 90px;
            width: 390px;
            ul{
                padding-inline-start: 0!important;
                width: 440px;
            }
            li{
                list-style: none;
                float: left;
                margin-left: 10px;
            }
        }
        .title{
            font-size: 24px;
            font-weight: 500;
            color: #208BFF;
            line-height: 56px;
            height: 56px;
            -webkit-animation: Glow 1.5s ease infinite alternate;
            animation: Glow 1.5s ease infinite alternate;
        }
        @-webkit-keyframes Glow {
            from {
                text-shadow: 0 0 2px #fff,
                0 0 20px #208BFF,
                0 0 30px #208BFF,
                0 0 40px #208BFF
            }
            to {
                text-shadow: 0 0 3px #208BFF
            }
        }
        .dev-container{
            background: linear-gradient(180deg, #04172E 0%, rgba(17, 27, 57, 0.54) 100%);
            height: 244px;
            width: 100%;
            padding-top:10px;
            .dev-week{
                width: 186px;
                height: 30px;
                background: url("../../assets/kaifazhou.png") no-repeat center;
                background-size: cover;
                font-size: 18px;
                display: flex;
                align-items: center;
                padding-left: 40px;
            }
            .dev-week-box{
                height: 80px;
                width: calc(100% - 30px);
                display: flex;
                margin-top: 10px;
                align-items: center;
                padding: 0 15px 0 15px;
                .dev-week-box-item{
                    float: left;
                    height: 80px;
                    width: 80px;
                }
            }
        }
        .my-progress-dev{
            position: relative;
            .progress-text{
                color: white;
                font-size: 18px;
                position: absolute;
                top: 20px;
                left: 20px;
            }
        }
        .my-progress-test{
            position: relative;
            .progress-text{
                color: white;
                font-size: 18px;
                position: absolute;
                top: 20px;
                left: 20px;
            }
        }
    }
</style>
<style lang="scss">
    .RightSideMiddle-container {
        .my-progress-dev svg > path:nth-child(2) {
            stroke: url(#blue)!important;
        }

        .my-progress-dev .el-progress-circle__track {
           stroke: rgba(0, 122, 255, 0.3) !important;
        }
        .my-progress-test svg > path:nth-child(2) {
            stroke: url(#red)!important;
        }

        .my-progress-test .el-progress-circle__track {
            stroke: #05745f !important;
        }
        .el-progress__text{
            display: none!important;
        }
    }
</style>
