<template>
    <div class="RightSideBottom-container module-container">
        <div class="title">当日请假人员</div>
        <div class="content_top_border"></div>
        <div class="holiday-container" v-if="gettersStaffData.leave.length === 0">
            <img src="../../assets/blue-start.png" alt="">
            <img style="position: absolute;" src="../../assets/fly-bg.png" alt="">
            <img style="position: absolute;right: 0" src="../../assets/right-half.png" alt="">
            <div class="blue-text">
                <div class="top">全员</div>
                <div class="bottom">执行任务</div>
            </div>
        </div>
        <div class="holiday-container-many" v-else>
            <div v-if="gettersStaffData.leave.length < 5" class="holiday-container-many-box">
                <div class="holiday-have-bg" v-for="item in gettersStaffData.leave">
                    <div class="holiday-left">
                        <img src="../../assets/man.png" alt="">
                  <!--      <img v-else  src="../../assets/women.png" alt="">-->
                    </div>
                    <div class="holiday-right">
                        <div class="name">{{item.name}}</div>
                        <div class="time">{{item.time}}</div>
                    </div>
                </div>
            </div>

            <div  v-else>
                <vue-scroll
                        :data="gettersStaffData.leave" :class-option="optionLeft"
                        :style="{width:seamlessWidth + 'px'}"
                        class="seamless-warp2">
                    <ul class="item"
                        :style="{width:seamlessUlWidth + 'px'}"
                    >
                        <li v-for="item in gettersStaffData.leave">
                            <div class="holiday-have-bg">
                                <div class="holiday-left">
                                    <img  src="../../assets/man.png" alt="">
                                <!--    <img v-if="item.sex === '女'" src="../../assets/women.png" alt="">-->
                                </div>
                                <div class="holiday-right">
                                    <div class="name">{{item.name}}</div>
                                    <div class="time">{{item.time}}</div>
                                </div>
                            </div>
                        </li>
                    </ul>
                </vue-scroll>
            </div>
        </div>
        <div class="content_bottom_border"></div>
    </div>
</template>

<script>
import vueScroll from 'vue-seamless-scroll'
import { mapGetters,mapActions } from 'vuex'
export default {

  name: "RightSideBottom",

  data() {
    return {

    }
  },
  mounted() {

  },

  components: {
    vueScroll
  },
  computed: {
    ...mapGetters([
      'gettersStaffData'
    ]),
    optionLeft () {
      return {
        direction: 2,
        limitMoveNum: 2
      }
    },
    seamlessWidth(){
      return this.gettersStaffData.leave.length * 100
    },
    seamlessUlWidth(){
      if(this.gettersStaffData.leave.length < 4){
        return this.seamlessWidth
      }else {
        return this.seamlessWidth + (this.gettersStaffData.leave.length * 10)
      }
    }
  },
  methods: {}

}
</script>

<style scoped lang="scss">
    .RightSideBottom-container {
        padding-left: 18px;
        .seamless-warp2 {
            overflow: hidden;
            height: 90px;
            width: 388px;
            ul{
                padding-inline-start: 0!important;
                width: 388px;
            }
            li{
                list-style: none;
                float: left;
            }
        }
        .title{
            font-size: 24px;
            font-weight: 500;
            height: 56px;
            color: #208BFF;
            line-height: 56px;
            -webkit-animation: Glow 1.5s ease infinite alternate;
            animation: Glow 1.5s ease infinite alternate;
        }
        @-webkit-keyframes Glow {
            from {
                text-shadow: 0 0 2px #fff,
                0 0 20px #208BFF,
                0 0 30px #208BFF,
                0 0 40px #208BFF
            }
            to {
                text-shadow: 0 0 3px #208BFF
            }
        }
        .holiday-container{
            background: linear-gradient(180deg, #04172E 0%, rgba(17, 27, 57, 0.54) 100%);
            background-size: cover;
            height: 102px;
            overflow: hidden;
            width: 100%;
            display: flex;
            align-items: center;
            position: relative;
            padding-top: 4px;
            .blue-text{
                position: absolute;
                right: 70px;
                font-size: 20px;
                color: #b0d1f1;
                .top{
                   text-align: center;
                }
                .bottom{

                }
            }
            .holiday-bg{
                width: 100%;
                height: 132px;
                img{
                    width: 100%;
                    height: 100%;
                }
            }

        }
        .holiday-container-many{
            background: linear-gradient(180deg, #04172E 0%, rgba(17, 27, 57, 0.54) 100%);
            height: 102px;
            width: 100%;
            display: flex;
            padding-top: 4px;
            align-items: center;
            .holiday-have-bg{
                display: flex;
                height: 90px;
                justify-content: center;
                width: 100px;
                .holiday-right{
                    .name{
                        font-size: 20px;
                    }
                    .time{
                        margin-top: 15px;
                        font-size: 14px;
                    }
                }
            }
        }
        .holiday-container-many-box{
            display: flex;
            margin-top: 20px;
        }
    }
</style>
