<template>
  <div class="module-container LeftSideBottom">
    <div class="module_title">团队概况</div>
    <div class="content_top_border"></div>
    <div class="module_content">
      <div id="chartsBox"></div>
      <div class="leftCharts">
        <div class="leftColorCharts" :style="{height:computedLeftHeight+'px'}"></div>
      </div>
      <div class="rightCharts">
        <div class="rightColorCharts" :style="{height:computedRightHeight+'px'}"></div>
      </div>
    </div>
    <div class="content_bottom_border"></div>
  </div>
</template>
<script>
import echarts from '../../lib/echarts'
import { mapGetters } from 'vuex'
export default {
  components: {},
  name: 'LeftSideBottom',
  data() {
    return {
      allNum: 0,
      womenNum: 0,
      menNum: 0
    }
  },
  methods: {
    initCharts() {
      let myChart = echarts.init(document.getElementById('chartsBox'))
      const colorList = ['#FAAA54','#208BFF'];
      const chartsDatas = [];
      const resData = this.gettersStaffData.teamGroupSex;
      this.allNum = 0;
      for (let i = 0; i < resData.length; i++) {
        chartsDatas.unshift({
          value: resData[i].num,
          name: resData[i].label,
          itemStyle: {
            normal: {
              color: colorList[i],
              borderWidth: 1,
              shadowBlur: 1,
              borderColor: colorList[i],
              shadowColor: colorList[i]
            }
          }
        }, {
          value: resData[0].num / 10,
          name: '',
          itemStyle: {
            normal: {
              label: {
                show: false
              },
              labelLine: {
                show: false
              },
              color: 'rgba(0, 0, 0, 0)',
              borderColor: 'rgba(0, 0, 0, 0)',
              borderWidth: 0
            }
          }
        });
        this.allNum += resData[i].num;
        if (resData[i].label == '男') {
          this.menNum = resData[i].num;
        } else {
          this.womenNum = resData[i].num;
        }
      }
      let options = {
        color: colorList,
        graphic: {
          elements: [{
              type: 'image',
              z: 3,
              style: {
                image: require("../../assets/circleBg.png"),
                width: 100,
                height: 100
              },
              left: 'center',
              top: 'center',
              position: [100, 100]
            },
            {
              type: 'image',
              z: 3,
              style: {
                image: require("../../assets/women.png"),
                width: 30,
                height: 60
              },
              right: '36%',
              top: 'center'
            },
            {
              type: 'image',
              z: 3,
              style: {
                image: require("../../assets/men.png"),
                width: 30,
                height: 60
              },
              left: '36%',
              top: 'center'
            }
          ]
        },
        tooltip: {
          show: false
        },
        toolbox: {
          show: false
        },
        series: [{
          name: '',
          type: 'pie',
          clockWise: false,
          radius: [62, 70],
          hoverAnimation: false,
          itemStyle: {
            normal: {
              label: {
                color: '#D1E4FF',
                show: true,
                fontSize: 18,
                formatter(params) {
                  return params.name ?
                    params.name + '\n' + params.value + '人' :
                    '';
                }
              },
              labelLine: {
                width: 4,
                length: 30,
                length2: 50,
                show: true,
                top:0,
                color: '#00ffff'
              }
            }
          },
          data: chartsDatas
        }]
      };
      myChart.setOption(options)
    }
  },
  computed: {
    ...mapGetters([
      'gettersStaffData'
    ]),
    computedLeftHeight() {
      if (this.allNum !== 0) {
        return parseInt(this.menNum / this.allNum * 58);
      }
    },
    computedRightHeight() {
      if (this.allNum !== 0) {
        return parseInt(this.womenNum / this.allNum * 58);
      }
    }
  },
  created() {},
  mounted() {
    let that = this;
    setTimeout(() => {
      that.initCharts();
    }, 2000)
    // this.$nextTick(() => {

    // })
  }
}
</script>
<style scoped lang="scss">
.LeftSideBottom {
  height: 100%;

  .module_content {
    overflow: hidden;
    background: linear-gradient(180deg, #04172E 0%, rgba(17, 27, 57, 0.54) 100%);
    height: calc(100% - 64px);
    align-items: center;
    position: relative;

    #chartsBox {
      height: 100%;
    }

    .leftCharts {
      background: url('../../assets/leftCharts.png');
      position: absolute;
      left: 68px;
      bottom: 20px;
      width: 46px;
      height: 58px;
      z-index: 3;

      .leftColorCharts {
        background: url('../../assets/leftColorCharts.png') no-repeat right bottom;
        position: absolute;
        left: 0px;
        bottom: 0px;
        width: 46px;
        height: 58px;
        z-index: 3;
      }
    }

    .rightCharts {
      background: url(../../assets/rightCharts.png);
      position: absolute;
      right: 68px;
      bottom: 20px;
      width: 46px;
      height: 58px;
      z-index: 3;

      .rightColorCharts {
        background: url('../../assets/rightColorCharts.png') no-repeat right bottom;
        position: absolute;
        left: 0px;
        bottom: 0px;
        width: 46px;
        height: 58px;
        z-index: 3;
      }
    }
  }
}
</style>