<template>
    <div class="missions-caps-container">
        <div class="missions-name">{{realName}}</div>
        <div class="missions-progress">
            <div class="missions-progress-item"
                 :style="{ background:realColor(i) }"
                 v-for="(i,index) in progressList"
                 :key="index"
            >
            </div>
        </div>
        <div class="missions-num">{{total}}</div>
    </div>
</template>

<script>

export default {

  name: "missions-caps",
  props:{
    realName:{
      type:String,
      default:()=>''
    },
    finished:{
      type:Number,
      default:()=>0
    },
    doing:{
      type:Number,
      default:()=>0
    },
    delay:{
      type:Number,
      default:()=>0
    },
    total:{
      type:Number,
      default:()=>0
    },
  },
  data() {
    return {
      delayCounts:0,
      delayIndex:[],
      doingCounts:0,
      doingIndex:[],
      finishedCounts:0,
      finishedIndex:[],
      progressList:[],
      allTotal:0
    }
  },
  computed:{


  },
  created(){
    this.allTotal = this.delay + this.finished + this.doing
    for (let i = 0; i < 10; i++) {
      this.progressList.push({
        type:''
      })
    }
  },
  mounted() {
    if(this.allTotal > 10){
      if(this.delay === 0){
        this.delay = 0
      }else {
        this.delayCounts = Math.ceil(parseFloat(this.delay/this.allTotal)*10)
        for (let i = 0; i < this.delayCounts; i++) {
          this.delayIndex.push(i)
        }
      }
      if(this.doing === 0){
        this.doing = 0
      }else {
        this.doingCounts = Math.ceil(parseFloat(this.doing/this.allTotal)*10)
        for (let i = this.delayCounts; i < this.doingCounts + this.delayCounts; i++) {
          this.doingIndex.push(i)
        }
      }
      if(this.finished === 0){
        this.finishedCounts = 0
      }else {
        this.finishedCounts = 10 - this.delayCounts - this.doingCounts
        for (let i = this.doingCounts + this.delayCounts; i < 10; i++) {
          this.finishedIndex.push(i)
        }
      }
    }else {
      this.delayCounts = this.delay
      for (let i = 0; i < this.delayCounts; i++) {
        this.delayIndex.push(i)
      }
      this.doingCounts = this.doing
      for (let i = this.delayCounts; i < this.doingCounts + this.delayCounts; i++) {
        this.doingIndex.push(i)
      }
      this.finishedCounts = this.finished
      for (let i = this.doingCounts + this.delayCounts; i <  this.allTotal ; i++) {
        this.finishedIndex.push(i)
      }
    }
    this.progressList.map((item,index)=>{
      if(this.delayIndex.includes(index)){
        item.type = 'delay'
      }
      if(this.doingIndex.includes(index)){
        item.type = 'doing'
      }
      if(this.finishedIndex.includes(index)){
        item.type = 'finished'
      }
    })

  },

  components: {},

  methods: {
    realColor(i){
        switch (i.type) {
          case 'delay':
            return '#E23333'
          case 'doing':
            return '#62F4F2'
          case 'finished':
            return '#549FD5'
        }
    }
  }

}
</script>

<style scoped>
    .missions-caps-container {
        display: flex;
        height: 40px;
        align-items: center;
        font-size: 18px;
    }
    .missions-name{
        width: 20%;
        display: flex;
        color: #CBDFFC;
        justify-content: center;
        align-items: center;
    }
    .missions-progress{
        width: 70%;
        display: flex;
        justify-content: center;
        align-items: center;
    }
    .missions-progress-item{
        width: 20px;
        height: 3px;
        background: #424868;
        margin-left: 10px;
    }
    .missions-num{
        width: 10%;
        display: flex;
        justify-content: center;
        align-items: center;
        color: #CBDFFC;
    }

</style>
