<template>
  <div class="staff-item" :class="tabType !=='workLoad'?'red-staff-item':''">
    <div class="staff-box">
      <div class="avatarPng">
        <img class="avatarImg" :src="`/images/${itemData.realName}.png`" alt="" onerror="this.src='/images/touxiang.png'">
        <img class="queenImg" v-if="rankNumber === 0" src='../assets/VIP.png' alt="">
        <img class="queenImg" v-if="rankNumber === 1" src='../assets/V1.png' alt="">
        <img class="queenImg" v-if="rankNumber === 2" src='../assets/V2.png' alt="">
        <img class="queenImg" v-if="rankNumber === 3" src='../assets/V3.png' alt="">
        <div class="maskBox">
          <span style="color:#fff">{{itemData.realName}}</span>
        </div>
      </div>
      <div class="infoBox">
        <!-- <div class="userInfo">
          <div class="rankBox">
            <img src="../assets/huangguan.png">
            <span>排名：NO.{{rankNumber+1}}</span>
          </div>
          <div class="nameBox">{{itemData.realName}}</div>
          <div class="jobBox">{{jobCn[itemData.role]}}</div>
        </div> -->
        <div class="barWildBox">
          <div class="weekRanks">
            <div class="barTitle">{{tabType=='bug'?'处理数':'任务预计(时)'}}</div>
            <div class="barBox">
              <div class="colorBar" v-if="tabType=='bug'" :style="{width:computedBug(itemData,'finish')}"></div>
              <div class="colorBar" v-else :style="{width:computedWidth(itemData.estimate)}"></div>
            </div>
            <div v-if="tabType=='bug'">{{itemData.finished}}</div>
            <div v-else class="barNum">{{itemData.estimate}}</div>
          </div>
          <div class="rankHour">
            <div class="barTitle">{{tabType=='bug'?'延期数':'任务实际(时)'}}</div>
            <div class="barBox">
              <div class="colorBar2" v-if="tabType=='bug'" :style="{width:computedBug(itemData,'delay')}"></div>
              <div class="colorBar2" v-else :style="{width:computedWidth(itemData.reality)}"></div>
            </div>
            <div v-if="tabType=='bug'">{{itemData.delay}}</div>
            <div v-else class="barNum">{{itemData.reality}}</div>
          </div>
          <div class="workLoad">
            <div class="barTitle">{{tabType=='bug'?'本周bug数':'工作负载'}}</div>
            <div class="barBox">
              <span v-if="tabType=='bug'">{{itemData.total}}个</span>
              <span v-else>{{itemData.workload}}%</span>
            </div>
          </div>
        </div>
      </div>   
    </div>
    <div class="line-box" v-if="rankNumber < 3">
      <img v-if="tabType !=='workLoad'" src="../assets/a_red_line.png" alt="">
      <img v-else src="../assets/a_blue_line.png" alt="">
    </div>
  </div>
</template>
<script>
export default {
  name: 'StaffItem',
  data() {
    return {
      jobCn: {
        'dev': '后端',
        'web': '前端'
      },
      srcUrlStr:"`/images/${itemData.realName}.png`"
    }
  },
  props: {
    itemData: {
      type: Object
    },
    rankNumber: {
      type: Number
    },
    tabType: {
      type: String
    }
  },
  methods: {
    loadDefault(){
      this.srcUrlStr="/images/touxiang.png";
    },
    computedBug(item,type) {
      if (type == 'finish') {
        return parseInt(Number(item.finished) / Number(item.total) * 100) + '%';
      }else{
      	return parseInt(Number(item.delay) / Number(item.total) * 100) + '%';
      }
    },
    computedWidth(item) {
      if (item > 100) {
        item = 100;
      }
      return item + '%';
    }
  }
}
</script>
<style lang="scss" scoped>
.staff-item {
  display: flex;
  flex-direction: column;
  .staff-box {
    display: flex;
    flex-direction: row;
  }
  .line-box {
    width: 100%;
    // background: url('../assets/a_red_line.png');
    img {
      width: unset;
      height: unset;
      position: unset!important;
    }
  }

  .avatarPng {
    width: 85px;
    height: 82px;
    margin-right: 12px;
    background: url('../assets/avatar2.png');
    position: relative;
    z-index:1;
    .avatarImg{
      width: 64px;
      height: 64px;
      display: inline-block;
      margin-top: 10px;
      margin-left: 10px;
    }
    .queenImg {
      width: 39px;
      height: 36px;
      position: absolute;
      top: -13px!important;
      left: -10px!important;
    }
    .maskBox {
      z-index: 2;
      text-align: center;
      width: 66px;
      height: 25px;
      line-height: 25px;
      position: absolute;
      left: 9px;
      bottom: 8px;
      background: #000;
      opacity: 0.6;
      span {
        font-size: 18px;
        font-weight: 500;
        color: #CBDFFC;
      }
    }
  }

  .infoBox {
    width: calc(100% - 85px);
    display: flex;
    flex-direction: row;

    .userInfo {
      width: 100px;
      margin-right: 40px;

      .rankBox {
        position: relative;
        color: #CBDFFC;
        font-size: 14px;
        margin-bottom: 5px;

        img {
          width: 21px;
          height: 14px;
        }

        span {
          margin-left: 30px;
        }
      }

      .nameBox {
        font-size: 16px;
        color: #CBDFFC;
        margin-bottom: 5px;
      }

      .jobBox {
        color: #BABABA;
        font-size: 14px;
      }

    }

    .barWildBox {
      flex: 1;
      margin-top: 10px;

      &>div {
        display: flex;
        flex-direction: row;
        align-items: center;
      }

      .weekRanks {
        margin-bottom: 5px;
      }

      .rankHour {
        margin-bottom: 5px;
      }

      .barTitle {
        color: #BABABA;
        width: 95px;
        font-size: 14px;
      }

      .barBox {
        font-size: 18px;
        color: #CBDFFC;
        width: calc(100% - 95px);
        margin-right: 5px;
        overflow: hidden;

        /*        display: flex;
        flex-direction: column;
        justify-content: space-around;*/
        .colorBar {
          width: 1px;
          background: linear-gradient(to left, #208BFF, #1F426C);
          height: 10px;
        }
        .colorBar2 {
          width: 1px;
          background: linear-gradient(90deg, #15473F 0%, #09866D 100%);
          height: 10px;          
        }
      }
    }
  }
}

.staff-item:not(last-child) {
  margin-bottom: 16px;
}

.red-staff-item {
  .colorBar {
    background: linear-gradient(to left, #580202, #E23333)!important;
  }
  .colorBar2 {
    background: linear-gradient(270deg, #FFAD54 0%, #8A6553 100%)!important;
  }
  .barTitle{
  	width: 80px;
  }
  .infoBox{
    // background: url('../assets/red-line.png');
  }
}
</style>