<template>
  <div class="module-container leftSideMiddle">
    <div class="module_title">年龄占比</div>
    <div class="content_top_border"></div>
    <div class="module_content">
      <div class="itemBox" v-for="item in gettersStaffData.teamGroupAge">
        <div class="titleSpan">{{item.label}}<span v-if="item.label!=='24以下'">岁</span></div>
        <div class="personSpan">{{item.num}}人</div>
        <div class="bgBarBox">
          <div class="bgBar"></div>
          <div class="colorBar" :style="{width:colorBarWidth(item.num)}"></div>
        </div>
      </div>
    </div>
    <div class="content_bottom_border"></div>
  </div>
</template>
<script>
import { mapGetters, mapActions } from 'vuex'
export default {
  components: {},
  name: 'LeftSideMiddle',
  data() {
    return {
      allNum: 0
    }
  },
  methods: {
    colorBarWidth(item) {
      let allNum = 0;
      if (this.gettersStaffData.teamGroupAge.length) {
        this.gettersStaffData.teamGroupAge.map((inside) => {
          allNum += inside.num
        })
      }
      return parseInt(item / allNum * 100) + '%';
    }
  },
  computed: {
    ...mapGetters([
      'gettersStaffData'
    ])
  },
  created() {

  }
}
</script>
<style scoped lang="scss">
.leftSideMiddle {
  height: 100%;

  .module_content {
    height: calc(100% - 80px);
    padding: 8px 16px;
    background: linear-gradient(180deg, #04172E 0%, rgba(17, 27, 57, 0.54) 100%);

    .itemBox:not(last-child) {
      margin-bottom: 16px;
    }

    .itemBox {
      height: 28px;
      display: flex;
      flex-direction: row;
      align-items: center;

      .titleSpan {
        font-size: 20px;
        width: 100px;
        color: #CBDFFC;
      }

      .personSpan {
        font-size: 16px;
        width: 58px;
        color: #208BFF;
      }

      .bgBarBox {
        width: calc(100% - 158px);
        height: 100%;
        position: relative;

        .bgBar {
          position: absolute;
          width: 100%;
          height: 100%;
          top: 0px;
          left: 0px;
          background: #58A7E0;
          opacity: 0.2;
          border-top-right-radius: 20px;
          border-bottom-right-radius: 20px;
        }

        .colorBar {
          position: absolute;
          width: 0px;
          height: 100%;
          top: 0px;
          left: 0px;
          border-top-right-radius: 20px;
          border-bottom-right-radius: 20px;
          transition: width 5s;
          background: linear-gradient(to left, #208BFF, #1F426C);
          z-index: 2;
        }
      }
    }

    .itemBox:nth-child(odd) {
      .bgBar {
        background: #F9AA54;
      }

      .personSpan {
        color: #FFAD54;
      }

      .colorBar {
        background: linear-gradient(to left, #FFAD54, #8A6553);
      }
    }
  }
}
</style>