<template>
    <div class="RightSideTop-container">
        <div class="head-container">
            <div class="head-container-1">
                <div class="head-container-1-p1">任务统计</div>
                <div class="head-container-1-p2">
                    <span class="head-container-1-num">{{gettersTaskNum}}</span>
                    <span class="head-container-1-text">个</span>
                </div>
            </div>
            <div class="head-container-2">
                <span class="program-item color-1-1">
                    <span class="program-item-it color-1"></span>
                    进行中
                </span>
                <span class="program-item color-2-2">
                       <span class="program-item-it color-2"></span>
                    已完成
                </span>
                <span class="program-item color-3-3">
                       <span class="program-item-it color-3"></span>
                    已超时
                </span>
            </div>
        </div>
        <div class="top-interface-1"></div>
        <div class="body-container" :style="{ height:height+'px' }" ref="bodyContainer">
            <vue-scroll :data="gettersTaskInfo"
                        v-if="isScroll"
                        class="seamless-warp"
                        :class-option="classOption"
                        :style="{height:seamlessHeight + 'px'}"
            >
                <ul class="item"
                    :style="{height:seamlessUlHeight + 'px'}"
                >
                    <li v-for="(i,index) in gettersTaskInfo">
                        <mission-cap
                                :key="index"
                                :realName="i.realName"
                                :total="i.total"
                                :delay="i.delay"
                                :doing="i.doing"
                                :finished="i.finished"
                        ></mission-cap>
                    </li>
                </ul>
            </vue-scroll>
            <mission-cap
                    :key="index"
                    v-for="(i,index) in gettersTaskInfo"
                    v-else
                    :realName="i.realName"
                    :total="i.total"
                    :delay="i.delay"
                    :doing="i.doing"
                    :finished="i.finished"
            ></mission-cap>
        </div>
        <div class="top-interface-2"></div>
    </div>
</template>

<script>
import missionCap from '../../components/missions-caps'
import vueScroll from 'vue-seamless-scroll'
import { mapGetters,mapActions } from 'vuex'
export default {

  name: "RightSideTop",

  data() {
    return {
      allTask:0,
      isScroll:false,
    }
  },
  computed:{
    ...mapGetters([
      'gettersTaskInfo',
      'gettersTaskNum'
    ]),
    classOption () {
      return {
        step:0.5,
      }
    },
    seamlessHeight(){
      return this.gettersTaskInfo.length * 40
    },
    seamlessUlHeight(){
      if(this.gettersTaskInfo.length < Math.ceil(this.height/40)){
        return this.seamlessHeight
      }else {
        return (this.seamlessHeight - this.gettersTaskInfo.length)
          +
          Math.ceil(this.gettersTaskInfo.length/10)
      }
    },
    height(){
      return  (document.documentElement.clientHeight || document.body.clientHeight) - (96+100+310+168+50)
    },

  },
  mounted() {
    this.getTaskData()
    const _this = this
    setTimeout(()=>{
      if(_this.seamlessHeight  > (_this.height)){
        _this.isScroll = true
      }else {
        _this.isScroll = false
      }
    },1000)

  },

  components: {
    missionCap,
    vueScroll
  },

  methods: {
    ...mapActions([
      'getTaskData',
    ])
  }

}
</script>

<style scoped  lang="scss">
    .RightSideTop-container {
        padding-left:18px;
        height: 450px;
        .seamless-warp {
            overflow: hidden;
            ul{
                padding-inline-start: 0!important;
                scroll-snap-margin-block-end: 0.5em;
                scroll-snap-margin-block-start: 0em;
            }
            li{
                list-style: none;
            }
        }
        .head-container{
            height: auto;
            display: flex;
            width: 100%;
            flex-flow: column;
        }
        .head-container-1{
            display: flex;
            height: 56px;
            line-height: 56px;
            justify-content: space-between;
        }
        .head-container-2{
            display: flex;
            align-items: center;
            justify-content: flex-end;
            margin-bottom:5px;
        }
        .program-item{
            font-size: 16px;
        }
        .program-item-it{
            width: 8px;
            height: 8px;
            display: inline-block;
            background: red;
            margin-left: 20px;
        }
        .head-container-1-p1{
            font-size: 24px;
            color: #208BFF;
            line-height: 56px;
            font-size: 24px;
            font-weight: 500;
            -webkit-animation: Glow 1.5s ease infinite alternate;
            animation: Glow 1.5s ease infinite alternate;

        }
        @-webkit-keyframes Glow {
            from {
                text-shadow: 0 0 2px #fff,
                0 0 20px #208BFF,
                0 0 30px #208BFF,
                0 0 40px #208BFF
            }
            to {
                text-shadow: 0 0 3px #208BFF
            }
        }
        .head-container-1-p2{
            text-align: right;
        }
        .head-container-1-num{
            font-size: 36px;
            color: #D1E4FF;
        }
        .head-container-1-text{
            font-size: 12px;
            color: #D1E4FF;
        }
        .body-container{
            position: relative;
            height: 360px;
            overflow: hidden;
            padding:10px;
            background: linear-gradient(180deg, #04172E 0%, rgba(17, 27, 57, 0.54) 100%);
        }
        .color-1-1{
            color: #62F4F2;
        }
        .color-2-2{
            color: #549FD5;
        }
        .color-3-3{
            color: #E23333;
        }
        .color-1{
            background: #62F4F2;
        }
        .color-2{
            background: #549FD5;
        }
        .color-3{
            background: #E23333;
        }
        .top-interface-1{
            height: 4px;
            background-image: linear-gradient(90deg,#081328,#0A2D51, #208BFF, #0A2D51,#081328);
            filter: blur(2px);

        }
        .top-interface-2{
            height: 4px;
            background-image: linear-gradient(90deg,#081328,#0A2D51, #208BFF, #0A2D51,#081328);
            filter: blur(2px);
        }
    }
</style>
